/**
 * @fileoverview Alert constants.
 * @module module/Alert/constants
 */

import { TRANSITION_COLORS } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

export const CLS = Object.freeze({
    ROOT:    'alert',
    ICON:    'alert-icon',
    CONTENT: 'alert-content',
    TITLE:   'alert-title',
    MESSAGE: 'alert-message',
    CLOSE:   'alert-close',
    HIDDEN:  'is-hidden',
});

export const DEFAULTS = Object.freeze({
    variant: 'info',        // info | success | warning | danger
    title: '',
    message: '',
    closable: false,
    icon: true,
    onClose: null,
});

export const ICONS = Object.freeze({
    info:    '<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="16" x2="12" y2="12"/><line x1="12" y1="8" x2="12.01" y2="8"/></svg>',
    success: '<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>',
    warning: '<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>',
    danger:  '<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>',
});

export const PART = defineParts('Alert', {
    ROOT        : { class: 'alert-container', aliases: ['root', 'container'] },
    ICON        : { class: 'alert-icon', aliases: ['icon'], tag: 'span' },
    CONTENT     : { class: 'alert-content', aliases: ['content'] },
    TITLE       : { class: 'alert-title', aliases: ['title'] },
    MESSAGE     : { class: 'alert-message', aliases: ['message'] },
    CLOSE       : { class: 'alert-close', aliases: ['close'], tag: 'span' },
    INFO        : { class: 'alert-info', aliases: ['info'] },
    SUCCESS     : { class: 'alert-success', aliases: ['success'] },
    WARNING     : { class: 'alert-warning', aliases: ['warning'] },
    DANGER      : { class: 'alert-danger', aliases: ['danger'] },
});

PART.ROOT.jit     = 'flex items-start gap-[var(--al-gap)] p-[var(--al-py)_var(--al-px)] rounded-[var(--al-radius)] [border:1px_solid_var(--al-border)] bg-[var(--al-bg)] fg-[var(--al-text)] [font-family:var(--al-font-stack)] text-[var(--al-font-size)] [transition:opacity_.2s,transform_.2s] {is-hidden}:opacity-0 {is-hidden}:[transform:translateY(-8px)] {is-hidden}:pointer-events-none';
PART.ICON.jit     = 'shrink-0 w-[1.25rem] h-[1.25rem] fg-[var(--al-icon-color)]';
PART.CONTENT.jit  = 'flex-1 min-w-0';
PART.TITLE.jit    = 'font-semibold fg-[var(--al-title-color)] [margin-bottom:0.25rem]';
PART.MESSAGE.jit  = 'fg-[var(--al-text)] [line-height:1.5]';
PART.CLOSE.jit    = 'shrink-0 flex items-center justify-center w-[1.25rem] h-[1.25rem] cursor-pointer fg-[var(--al-text)] opacity-50 hover:opacity-100 ' + TRANSITION_COLORS;
PART.INFO.jit     = '[--al-bg:var(--al-info-bg)] [--al-text:var(--al-info-text)] [--al-border:var(--al-info-border)] [--al-icon-color:var(--al-info-icon)] [--al-title-color:var(--al-info-title)]';
PART.SUCCESS.jit  = '[--al-bg:var(--al-success-bg)] [--al-text:var(--al-success-text)] [--al-border:var(--al-success-border)] [--al-icon-color:var(--al-success-icon)] [--al-title-color:var(--al-success-title)]';
PART.WARNING.jit  = '[--al-bg:var(--al-warning-bg)] [--al-text:var(--al-warning-text)] [--al-border:var(--al-warning-border)] [--al-icon-color:var(--al-warning-icon)] [--al-title-color:var(--al-warning-title)]';
PART.DANGER.jit   = '[--al-bg:var(--al-danger-bg)] [--al-text:var(--al-danger-text)] [--al-border:var(--al-danger-border)] [--al-icon-color:var(--al-danger-icon)] [--al-title-color:var(--al-danger-title)]';