/**
 * @fileoverview Alert view — DOM setup.
 * @module module/Alert/view
 */

import { CLS, PART, ICONS } from './constants.js';

export const SM_EFFECTS = {
    visible({ root }) { root.removeClass(CLS.HIDDEN); },
    hidden({ root })  { root.addClass(CLS.HIDDEN); },
};

export function setupDOM(root, config) {
    const { variant, title, message, closable, icon } = config;

    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);

    const variantMap = {
        info:    PART.INFO,
        success: PART.SUCCESS,
        warning: PART.WARNING,
        danger:  PART.DANGER,
    };
    if (variantMap[variant]) {
        variantMap[variant].apply(root);
    }

    root[0].setAttribute('role', 'alert');

    // Icon
    if (icon && ICONS[variant]) {
        const $icon = PART.ICON.create();
        $icon[0].innerHTML = ICONS[variant];
        root.append($icon);
    }

    // Content
    const $content = PART.CONTENT.create();
    root.append($content);

    if (title) {
        const $title = PART.TITLE.create();
        $title.text(title);
        $content.append($title);
    }

    if (message) {
        const $msg = PART.MESSAGE.create();
        $msg.text(message);
        $content.append($msg);
    }

    // Close button
    let closeBtn = null;
    if (closable) {
        closeBtn = PART.CLOSE.create({
            role: 'button',
            tabindex: '0',
            'aria-label': 'Close',
        });
        closeBtn[0].innerHTML = '&#x2715;';
        root.append(closeBtn);
    }

    return { closeBtn };
}

export function cleanupDOM(root) {
    root.removeClass(CLS.ROOT);
    root[0].innerHTML = '';
}
